          width: 32px;
          height: 32px;
          border-radius: 8px;
          display: inline-flex;
          align-items: center;
          justify-content: center;
          border: none;
          background: transparent;
          color: #71717A;
          transition: all 0.2s ease;
        }
        .btn-action-icon:hover {
          background: rgba(0, 0, 0, 0.04);
          color: #09090B;
        }
        .btn-action-icon.danger:hover {
          background: rgba(239, 68, 68, 0.1);
          color: #DC2626;
        }

        /* Main Container Card */
        .vision-card {
          background: rgba(255, 255, 255, 0.7);
          backdrop-filter: blur(24px) saturate(150%);
          -webkit-backdrop-filter: blur(24px) saturate(150%);
          border: 1px solid rgba(0, 0, 0, 0.04);
          border-radius: 16px;
          box-shadow: 0 4px 24px rgba(0, 0, 0, 0.02);
          padding: 24px;
        }

        /* Spotlight Search */
        .vision-search-wrapper {
          background: rgba(0, 0, 0, 0.02);
          border: 1px solid rgba(0, 0, 0, 0.04);
          border-radius: 12px;
          padding: 8px 16px;
          display: flex;
          align-items: center;
          gap: 10px;
          transition: all 0.2s cubic-bezier(0.16, 1, 0.3, 1);
          width: 100%;
          max-width: 340px;
        }
        .vision-search-wrapper:focus-within {
          background: #FFFFFF;
          border-color: rgba(249, 115, 22, 0.4);
          box-shadow: 0 0 0 3px rgba(249, 115, 22, 0.1), 0 4px 12px rgba(0, 0, 0, 0.03);
        }
        .vision-search-input {
          border: none;
          background: transparent;
          outline: none;
          width: 100%;
          font-size: 14px;
          color: #09090B;
        }
        .vision-search-input::placeholder {
          color: #A1A1AA;
        }

        /* Grid List Redesign (Replacing Table) */
        .vision-list-container {
          overflow-x: auto;
        }
        .vision-grid-row {
          display: grid;
          grid-template-columns: 40px 2fr 2fr 1.5fr 100px 100px 90px;
          align-items: center;
          min-width: 800px; /* Forces horizontal scroll on mobile */
        }

        .vision-header-row {
          font-size: 12px;
          font-weight: 600;
          color: #71717A;
          text-transform: uppercase;
          letter-spacing: 0.05em;
          padding: 0 16px 12px 16px;
          border-bottom: 1px solid rgba(0, 0, 0, 0.04);
          margin-bottom: 8px;
        }

        .vision-data-row {
          padding: 12px 16px;
          border-radius: 12px;
          transition: background 0.2s ease;
        }
        .vision-data-row:hover {
          background: rgba(0, 0, 0, 0.02);
        }

        /* Status Pills */
        .vision-pill {
          padding: 4px 10px;
          border-radius: 100px;
          font-size: 12px;
          font-weight: 600;
          display: inline-flex;
          align-items: center;
          gap: 6px;
          width: fit-content;
        }
        .pill-active {
          background: rgba(16, 185, 129, 0.1);
          color: #059669;
        }
        .pill-inactive {
          background: rgba(113, 113, 122, 0.1);
          color: #52525B;
        }

        .dot {
          width: 6px;
          height: 6px;
          border-radius: 50%;
        }
        .dot-active { background: #10B981; }
        .dot-inactive { background: #A1A1AA; }
      `}</style>

      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h1 className="vision-title">Branches</h1>
        <button className="btn-vision-brand" onClick={() => navigate('/branches/new')}>
          <i className="bi bi-plus" style={{ fontSize: 18 }} />
          <span>Add Branch</span>
        </button>
      </div>

      {/* Main Content Card */}
      <div className="vision-card">
        {/* Toolbar */}
        <div className="d-flex justify-content-between align-items-center mb-4">
          <div className="vision-search-wrapper">
            <i className="bi bi-search" style={{ color: '#A1A1AA', fontSize: 14 }} />
            <input
              className="vision-search-input"
              placeholder="Search branches or locations..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            {search && (
              <i 
                className="bi bi-x-circle-fill text-muted" 
                style={{ cursor: 'pointer', fontSize: 12 }} 
                onClick={() => setSearch('')}
              />
            )}
          </div>
        </div>

        {/* List / Grid Area */}
        {isLoading ? (
          <div className="d-flex flex-column justify-content-center align-items-center py-5" style={{ minHeight: 200 }}>
            <div className="spinner-border spinner-border-sm mb-3" style={{ color: '#F97316', width: '2rem', height: '2rem' }} />
            <span style={{ color: '#71717A', fontSize: 14, fontWeight: 500 }}>Loading branches...</span>
          </div>
        ) : (
          <div className="vision-list-container">
            {/* Header Row */}
            <div className="vision-grid-row vision-header-row">
              <div>#</div>
              <div>Name</div>
              <div>Location</div>
              <div>Manager</div>
              <div>Staff</div>
              <div>Status</div>
              <div className="text-end">Actions</div>
            </div>

            {/* Data Rows */}
            <div>
              {branches.length === 0 ? (
                <div className="text-center py-5">
                  <div style={{ width: 48, height: 48, background: 'rgba(0,0,0,0.02)', borderRadius: '50%', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', marginBottom: 12 }}>
                    <i className="bi bi-building text-muted" style={{ fontSize: 20 }} />
                  </div>
                  <h6 style={{ color: '#09090B', fontWeight: 600, margin: 0 }}>No branches found</h6>
                  <p style={{ color: '#71717A', fontSize: 14, marginTop: 4 }}>Adjust your search or add a new branch.</p>
                </div>
              ) : (
                branches.map((branch: any, i: number) => {
                  const isActive = branch.status === 'active';

                  return (
                    <div key={branch.id} className="vision-grid-row vision-data-row">
                      <div style={{ color: '#A1A1AA', fontSize: 13, fontWeight: 500 }}>
                        {(i + 1).toString().padStart(2, '0')}
                      </div>

                      <div>
                        <div style={{ color: '#09090B', fontWeight: 600, fontSize: 14 }}>{branch.name}</div>
                      </div>

                      <div className="d-flex align-items-center gap-2">
                        <i className="bi bi-geo-alt" style={{ color: '#A1A1AA', fontSize: 13 }} />
                        <span style={{ color: '#52525B', fontSize: 14 }}>{branch.location}</span>
                      </div>

                      <div className="d-flex align-items-center gap-2">
                        {branch.manager_name ? (
                          <>
                            <div style={{ width: 22, height: 22, borderRadius: '50%', background: 'rgba(249, 115, 22, 0.1)', color: '#EA580C', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 10, fontWeight: 700 }}>
                              {branch.manager_name[0].toUpperCase()}
                            </div>
                            <span style={{ color: '#3F3F46', fontSize: 14 }}>{branch.manager_name}</span>
                          </>
                        ) : (
                          <span style={{ color: '#A1A1AA', fontSize: 14 }}>Unassigned</span>
                        )}
                      </div>

                      <div style={{ color: '#52525B', fontSize: 14, fontWeight: 500 }}>
                        {branch.staff_count ?? '0'}
                      </div>

                      <div>
                        <span className={`vision-pill ${isActive ? 'pill-active' : 'pill-inactive'}`}>
                          <span className={`dot ${isActive ? 'dot-active' : 'dot-inactive'}`} />
                          <span style={{ textTransform: 'capitalize' }}>{branch.status}</span>
                        </span>
                      </div>

                      <div className="d-flex justify-content-end gap-1">
                        <button
                          className="btn-action-icon"
                          onClick={() => navigate(`/branches/${branch.id}/edit`)}
                          title="Edit Branch"
                        >
                          <i className="bi bi-pencil" style={{ fontSize: 14 }} />
                        </button>
                        <button
                          className="btn-action-icon danger"
                          onClick={() => {
                            if (window.confirm(`Are you sure you want to delete "${branch.name}"? This action cannot be undone.`)) {
                              deleteMutation.mutate(branch.id);
                            }
                          }}
                          title="Delete Branch"
                        >
                          <i className="bi bi-trash3" style={{ fontSize: 14 }} />
                        </button>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { departmentsApi, branchesApi, usersApi } from '../../services/api';
import type { DepartmentForm } from '../../types';

export default function DepartmentFormPage() {
  const { id } = useParams();
  const isEdit = Boolean(id);
  const navigate = useNavigate();
  const qc = useQueryClient();

  const { register, handleSubmit, reset, formState: { errors } } = useForm<DepartmentForm>({
    defaultValues: { status: 'active' },
  });

  const { data: deptRes } = useQuery({
    queryKey: ['department', id],
    queryFn: () => departmentsApi.getOne(Number(id)),
    enabled: isEdit,
  });

  const { data: branchesRes } = useQuery({ queryKey: ['branches'], queryFn: branchesApi.getAll });
  const { data: usersRes } = useQuery({ queryKey: ['users'], queryFn: usersApi.getAll });

  useEffect(() => {
    if (deptRes?.data) reset(deptRes.data as unknown as DepartmentForm);
  }, [deptRes, reset]);

  const mutation = useMutation({
    mutationFn: (data: DepartmentForm) =>
      isEdit ? departmentsApi.update(Number(id), data) : departmentsApi.create(data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['departments'] });
      navigate('/departments');
    },
  });

  return (
    <div className="vision-form-wrapper">
      <style>{`
        .vision-form-wrapper {
          font-family: -apple-system, BlinkMacSystemFont, "SF Pro Display", "Inter", sans-serif;
          padding: 8px;
        }

        /* Premium Header */
        .vision-header {
          display: flex;
          align-items: center;
          gap: 16px;
          margin-bottom: 32px;
        }

        .vision-back-btn {
          width: 36px;
          height: 36px;
          border-radius: 10px;
          border: 1px solid rgba(0, 0, 0, 0.06);
          background: #FFFFFF;
          display: flex;
          align-items: center;
          justify-content: center;
          color: #52525B;
          cursor: pointer;
          transition: all 0.2s cubic-bezier(0.16, 1, 0.3, 1);
          box-shadow: 0 1px 2px rgba(0,0,0,0.02);
        }
        .vision-back-btn:hover {
          background: #F4F4F5;
          color: #09090B;
          transform: translateX(-2px);
        }

        .vision-title {
          font-size: 24px;
          font-weight: 700;
          letter-spacing: -0.6px;
          color: #09090B;
          margin: 0;
        }

        /* Glassmorphic Form Card */
        .vision-form-card {
          background: rgba(255, 255, 255, 0.7);
          backdrop-filter: blur(32px) saturate(150%);
          -webkit-backdrop-filter: blur(32px) saturate(150%);
          border: 1px solid rgba(0, 0, 0, 0.05);
          border-radius: 20px;
          box-shadow: 0 12px 40px rgba(0, 0, 0, 0.03), 0 1px 3px rgba(0,0,0,0.01);
          padding: 32px;
          max-width: 540px;
        }

        /* Form Controls */
        .vision-form-group {
          margin-bottom: 24px;
        }

        .vision-label {
          display: block;
          font-size: 13px;
          font-weight: 600;
          color: #3F3F46;
          margin-bottom: 8px;
          letter-spacing: 0.2px;
        }

        .vision-input, .vision-select, .vision-textarea {
          width: 100%;
          background: rgba(0, 0, 0, 0.02);
          border: 1px solid rgba(0, 0, 0, 0.05);
          border-radius: 12px;
          padding: 12px 16px;
          font-size: 14px;
          color: #09090B;
          transition: all 0.2s cubic-bezier(0.16, 1, 0.3, 1);
          outline: none;
          box-shadow: inset 0 1px 2px rgba(0,0,0,0.01);
          font-family: inherit;
        }

        .vision-textarea {
          resize: vertical;
          min-height: 80px;
        }

        .vision-input::placeholder, .vision-textarea::placeholder {
          color: #A1A1AA;
        }

        .vision-input:focus, .vision-select:focus, .vision-textarea:focus {
          background: #FFFFFF;
          border-color: rgba(249, 115, 22, 0.4);
          box-shadow: 0 0 0 3px rgba(249, 115, 22, 0.1), 0 2px 8px rgba(0,0,0,0.02);
        }

        .vision-input.is-invalid {
          border-color: rgba(239, 68, 68, 0.4);
          background: rgba(239, 68, 68, 0.02);
        }
        .vision-input.is-invalid:focus {
          box-shadow: 0 0 0 3px rgba(239, 68, 68, 0.1);
        }

        /* Custom Select Wrapper */
        .vision-select {
          appearance: none;
          -webkit-appearance: none;
          cursor: pointer;
        }
        .vision-select-wrapper {
          position: relative;
        }
        .vision-select-wrapper::after {
          content: "";
          position: absolute;
          right: 16px;
          top: 50%;
          transform: translateY(-50%);
          width: 10px;
          height: 6px;
          background-color: #A1A1AA;
          clip-path: polygon(100% 0%, 0 0%, 50% 100%);
          pointer-events: none;
        }

        .vision-error-text {
          color: #EF4444;
          font-size: 12px;
          margin-top: 6px;
          font-weight: 500;
          display: flex;
          align-items: center;
          gap: 4px;
        }

        /* Alert Banner */
        .vision-alert-danger {
          background: rgba(239, 68, 68, 0.08);
          border: 1px solid rgba(239, 68, 68, 0.2);
          color: #DC2626;
          padding: 12px 16px;
          border-radius: 12px;
          font-size: 13px;
          font-weight: 500;
          display: flex;
          align-items: center;
          gap: 8px;
          margin-bottom: 24px;
        }

        /* Buttons */
        .vision-actions {
          display: flex;
          gap: 12px;
          margin-top: 32px;
          padding-top: 24px;
          border-top: 1px solid rgba(0, 0, 0, 0.04);
        }

